import{_ as e,o as t,c as r,ai as a}from"./chunks/framework.CpTXwe1b.js";const f=JSON.parse('{"title":"独行侠","description":"","frontmatter":{"title":"独行侠","date":"2015-08-23T13:33:43.327Z","length":"278字","time":"1分钟","aside":false,"hash":-484005470},"headers":[],"relativePath":"article/独行侠.md","filePath":"article/独行侠.md"}'),_={name:"article/独行侠.md"},s=a("<p>你是否曾独行，享受独行的乐趣<br> 虽然没有伴侣，却也无忧无虑<br> 当你一个人彳亍，漫步在小径上<br> 走过葱郁的大树，走过苍灰的草坪<br> 踩着雨后微湿的柏油路，脚边是一串落叶<br> 享受空旷的寂寞，享受宁静中的背景噪音<br> 这是只有你的角落，这儿的空气都归你呼吸<br> 这儿的阳光都照耀你，这儿的鸟只为你啾唧<br> 那种远离人群的氛围，可使人安静地坐上一整天<br> 想上一整天的问题，心随顿悟的海洋起伏<br> 写上一整天的诗文，书是最美的风景<br> 自己的小小世界，已充实得挤挤满满<br> 悲伤钻不进来，孤独唤不醒我<br> 让信息随文字过滤，思绪随时间沉淀<br> 此时我已完全陶醉于我的世界<br> 除了我心中的风筝，那头连着你<br> 是你告诉我<br> “这是绝对的自由，去吧美妙的独行”</p>",1),c=[s];function o(i,n,b,d,l,p){return t(),r("div",null,c)}const h=e(_,[["render",o]]);export{f as __pageData,h as default};
